arguments.new_str:
using Xunit;

namespace MyApp.Tests;

[TestCaseOrderer(typeof(AlphabeticalOrderer))]
public class OrderedTests
{
    [Fact]
    public void Test_A() => Assert.True(true);

    [Fact]
    public void Test_B() => Assert.True(true);
}

// Stub: implement ITestCaseOrderer to provide custom ordering
public class AlphabeticalOrderer : ITestCaseOrderer
{
    public IReadOnlyCollection<TTestCase> OrderTestCases<TTestCase>(IReadOnlyCollection<TTestCase> testCases)
        where TTestCase : notnull, ITestCase
    {
        return testCases.OrderBy(tc => tc.TestMethod?.MethodName).ToList();
    }
}

